// Functions
import { useState } from "react";
// Forms
import NavbarCustom from "./components/Navbar";
import CategoryCard from "./components/CategoryCard";
import LaptopForm from "./components/LaptopForm";
import PhoneForm from "./components/PhoneForm";
import TvForm from "./components/TvForm";
import HistoryForm from "./components/HistoryForm";

function App() {
  const [currentPage, setCurrentPage] = useState("home");
  // 'home', 'laptop', 'phone', 'tv' 'history'

  // Функция для перехода на историю после генерации
  const goToHistory = () => {
    setCurrentPage("history");
  };
  
  return (
    <>
      <NavbarCustom onNavClick={setCurrentPage} />
      <div className="container">
        <div className="row justify-content-center">
          <div className="col-md-8 col-lg-6">
            {currentPage === "home" && (
              <CategoryCard onCategoryClick={setCurrentPage} />
            )}
            {currentPage === "laptop" && <LaptopForm onGenerateComplete={goToHistory}/>}
            {currentPage === "phone" && <PhoneForm onGenerateComplete={goToHistory}/>}
            {currentPage === "tv" && <TvForm onGenerateComplete={goToHistory}/>}
            {currentPage === "history" && <HistoryForm />}
          </div>
        </div>
      </div>
    </>
  );
}
// Что бы можно было использовать этот компонент в других файлах
export default App;
